const item = items[0];
const now = Date.now();
// multipart/form-data: textová pole jsou pod item.json.body
const body = item.json.body || item.json;
const eventId = String(body.event || '').trim() || 'UNKNOWN';

// Načti binární data fotky (filesystem-v2 storage vyžaduje getBinaryDataBuffer)
let photoBase64 = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'photo');
  photoBase64 = buffer.toString('base64');
} catch(e1) {
  try {
    const buffer = await helpers.getBinaryDataBuffer(item, 'photo');
    photoBase64 = buffer.toString('base64');
  } catch(e2) {
    photoBase64 = (item.binary?.photo?.data ?? '').replace(/[\r\n\s]/g, '');
  }
}

return [{
  json: {
    team:            String(body.team || '').trim(),
    description:     String(body.description || '').trim(),
    eventId,
    branchName:      `submission/${eventId}-${now}`,
    photoRepoPath:   `public/images/submissions/${eventId}/${now}.jpg`,
    photoPublicPath: `/images/submissions/${eventId}/${now}.jpg`,
    activitiesPath:  `public/content/events/${eventId}/activities.json`,
    activityId:      String(now),
    photoBase64
  }
}];

const item = items[0];
const prep = $node['Připrav data'].json;
const ghFile = $node['Načti activities.json'].json;

// SHA existujícího souboru — nutné pro GitHub PUT update (bez SHA vrátí 422)
const activitiesSha = ghFile?.sha || null;

// Dekóduj stávající activities.json, nebo začni prázdný
let current = { eventId: prep.eventId, title: '', activities: [] };
if (ghFile && ghFile.content) {
  try {
    current = JSON.parse(Buffer.from(ghFile.content, 'base64').toString('utf-8'));
  } catch(e) {}
}

// Přidej novou aktivitu
current.activities = current.activities || [];
current.activities.push({
  id:          prep.activityId,
  title:       prep.team,
  description: prep.description,
  url:         '',
  btnLabel:    'Zobrazit',
  photo:       prep.photoPublicPath
});

const newActivitiesBase64 = Buffer.from(JSON.stringify(current, null, 2)).toString('base64');

return [{
  json: {
    ...prep,
    newActivitiesBase64,
    activitiesSha
  }
}];

// Připraví URL a body pro nahrání activities.json jako plain string
// (komplexní výrazy v HTTP Request URL/body polích v n8n mohou selhat s 'invalid syntax')
const d = $('Sestav activities.json').item.json;

const bodyObj = {
  message: 'submission: data ' + d.team,
  content: d.newActivitiesBase64,
  branch:  d.branchName
};
// SHA je povinné pokud soubor již existuje, jinak GitHub vrátí 422
if (d.activitiesSha) bodyObj.sha = d.activitiesSha;

return [{
  json: {
    uploadUrl:  'https://api.github.com/repos/chmelainv/AI-nadsenci-web/contents/' + d.activitiesPath,
    uploadBody: JSON.stringify(bodyObj),
    // metadata pro Vytvoř PR
    team:            d.team,
    description:     d.description,
    photoPublicPath: d.photoPublicPath,
    branchName:      d.branchName
  }
}];
